 1→type CurrencyValue = number | undefined | string;
 2→
 3→export const formatToCurrency = (fullValue: CurrencyValue): string => {
 4→  if (typeof fullValue === 'undefined') return `R$ 0,00`;
 5→
 6→  const [value, cents] = String(fullValue).replace('-', '').split('.');
 7→
 8→  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
 9→  let formattedValue = '';
10→
11→  for (let i = 0; i < value.length; i += 1) {
12→    const currentDigit = value[value.length - 1 - i];
13→
14→    if (i > 0 && i % 3 === 0) {
15→      formattedValue = `${currentDigit}.${formattedValue}`;
16→    } else {
17→      formattedValue = `${currentDigit}${formattedValue}`;
18→    }
19→  }
20→
21→  return `R$ ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents[0]}${
22→    formattedCents[1]
23→  }`;
24→};
25→
26→export function sanitizeTaxonomy(text: string): string {
27→  if (!text || typeof text !== 'string') {
28→    return '';
29→  }
30→
31→  return text
32→    .toLowerCase()
33→    .normalize('NFD')
34→    .replace(/[\u0300-\u036f]/g, '')
35→    .replace(/[^\w\s]/g, '')
36→    .replace(/\s+/g, '_')
37→    .replace(/_+/g, '_')
38→    .replace(/^_/, '')
39→    .replace(/_$/, '');
40→}
41→
42→export const getFormattedPoints = (n: number) => {
43→  const nfPtBR = new Intl.NumberFormat('pt-BR');
44→  return nfPtBR.format(Math.max(0, Math.floor(n || 0)));
45→};
46→
47→export const getParsedCurrency = (text: string) => {
48→  const digits = (text || '').replace(/\D/g, '');
49→  const n = parseInt(digits, 10);
50→  if (Number.isNaN(n)) {
51→    return 0;
52→  }
53→  return n / 100;
54→};
55→
56→export const getParsePoints = (text: string) => {
57→  const digits = (text || '').replace(/\D/g, '');
58→  const n = parseInt(digits, 10);
59→  return Number.isNaN(n) ? 0 : n;
60→};
61→
62→export const formatCurrencyBR = (n: number) =>
63→  new Intl.NumberFormat('pt-BR', {
64→    style: 'currency',
65→    currency: 'BRL',
66→  })
67→    .format(Number.isFinite(n) ? n : 0)
68→    .replace(/\s/g, '');
